import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, useNavigate, useLocation, Link } from 'react-router-dom';
import { 
  LayoutDashboard, 
  BookOpen, 
  Video, 
  UserCircle, 
  ChevronLeft,
  Bell
} from 'lucide-react';

// Pages
import Dashboard from './pages/Dashboard';
import Patrol from './pages/Patrol';
import Supervision from './pages/Supervision';
import Evaluation from './pages/Evaluation';
import Homework from './pages/Homework';
import Attendance from './pages/Attendance';
import Stats from './pages/Stats';
import Live from './pages/Live';

// Context
import { UserRole } from './types';

// Role Context
export const RoleContext = React.createContext<{
  role: UserRole;
  setRole: (role: UserRole) => void;
}>({ role: UserRole.TEACHER, setRole: () => {} });

// Layout Components
const Header = ({ title, canGoBack }: { title: string, canGoBack: boolean }) => {
  const navigate = useNavigate();
  return (
    <header className="sticky top-0 z-50 bg-white border-b border-gray-200 px-4 h-14 flex items-center justify-between shadow-sm">
      <div className="flex items-center gap-2">
        {canGoBack && (
          <button onClick={() => navigate(-1)} className="p-1 -ml-2 text-gray-600 active:bg-gray-100 rounded-full">
            <ChevronLeft size={24} />
          </button>
        )}
        <h1 className="text-lg font-bold text-gray-800 truncate max-w-[200px]">{title}</h1>
      </div>
      <div className="flex items-center gap-3">
        <button className="relative p-2 text-gray-600">
          <Bell size={20} />
          <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
        </button>
      </div>
    </header>
  );
};

const BottomNav = () => {
  const location = useLocation();
  const isActive = (path: string) => location.pathname === path;

  const navItems = [
    { path: '/', icon: LayoutDashboard, label: '工作台' },
    { path: '/live', icon: Video, label: '直播' },
    { path: '/profile', icon: UserCircle, label: '我的' },
  ];

  if (location.pathname !== '/' && location.pathname !== '/live' && location.pathname !== '/profile') {
    return null; // Hide on detail pages
  }

  return (
    <nav className="fixed bottom-0 left-0 right-0 bg-white border-t border-gray-200 pb-safe pt-2 px-6 h-16 flex justify-between items-center z-50">
      {navItems.map((item) => (
        <Link 
          key={item.path} 
          to={item.path} 
          className={`flex flex-col items-center gap-1 w-16 ${isActive(item.path) ? 'text-indigo-600' : 'text-gray-400'}`}
        >
          <item.icon size={24} strokeWidth={isActive(item.path) ? 2.5 : 2} />
          <span className="text-[10px] font-medium">{item.label}</span>
        </Link>
      ))}
    </nav>
  );
};

const ProfilePage = () => {
  const { role, setRole } = React.useContext(RoleContext);

  return (
    <div className="p-4 space-y-6">
      <div className="bg-white p-6 rounded-2xl shadow-sm flex items-center gap-4">
        <div className="w-16 h-16 bg-indigo-100 rounded-full flex items-center justify-center text-indigo-600 text-xl font-bold">
          {role === UserRole.TEACHER ? '张' : role === UserRole.STUDENT ? '李' : '王'}
        </div>
        <div>
          <h2 className="text-xl font-bold text-gray-900">
             {role === UserRole.TEACHER ? '张老师' : role === UserRole.STUDENT ? '李同学' : '王督导'}
          </h2>
          <p className="text-gray-500 text-sm">ID: 2023001</p>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm overflow-hidden">
        <div className="p-4 border-b border-gray-100 font-medium text-gray-700">切换角色 (演示用)</div>
        <div className="divide-y divide-gray-100">
          {[UserRole.TEACHER, UserRole.STUDENT, UserRole.SUPERVISOR].map((r) => (
            <button
              key={r}
              onClick={() => setRole(r)}
              className={`w-full text-left px-4 py-3 flex items-center justify-between ${role === r ? 'bg-indigo-50 text-indigo-700' : 'text-gray-600'}`}
            >
              <span>{r === UserRole.TEACHER ? '教师端' : r === UserRole.STUDENT ? '学生端' : '督导端'}</span>
              {role === r && <div className="w-2 h-2 rounded-full bg-indigo-600"></div>}
            </button>
          ))}
        </div>
      </div>

      <div className="text-center text-xs text-gray-400 mt-8">
        v1.0.2 Build 20231027
      </div>
    </div>
  );
};

const AppContent = () => {
  const location = useLocation();
  const getTitle = () => {
    switch(location.pathname) {
      case '/': return '智慧课堂';
      case '/patrol': return '在线巡课';
      case '/supervision': return '督导听课';
      case '/evaluation': return '随堂评教';
      case '/homework': return '课后作业';
      case '/attendance': return '考勤签到';
      case '/stats': return '课堂数据';
      case '/live': return '直播讲座';
      case '/profile': return '个人中心';
      default: return '智慧课堂';
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      <Header title={getTitle()} canGoBack={location.pathname !== '/' && location.pathname !== '/live' && location.pathname !== '/profile'} />
      <Routes>
        <Route path="/" element={<Dashboard />} />
        <Route path="/patrol" element={<Patrol />} />
        <Route path="/supervision" element={<Supervision />} />
        <Route path="/evaluation" element={<Evaluation />} />
        <Route path="/homework" element={<Homework />} />
        <Route path="/attendance" element={<Attendance />} />
        <Route path="/stats" element={<Stats />} />
        <Route path="/live" element={<Live />} />
        <Route path="/profile" element={<ProfilePage />} />
      </Routes>
      <BottomNav />
    </div>
  );
};

const App = () => {
  const [role, setRole] = useState<UserRole>(UserRole.TEACHER);

  return (
    <RoleContext.Provider value={{ role, setRole }}>
      <HashRouter>
        <AppContent />
      </HashRouter>
    </RoleContext.Provider>
  );
};

export default App;

import React, { useContext } from 'react';
import { Link } from 'react-router-dom';
import { RoleContext } from '../App';
import { UserRole } from '../types';
import { 
  ClipboardCheck, 
  Eye, 
  MessageSquare, 
  BookOpen, 
  CalendarCheck, 
  BarChart2, 
  PenTool,
  Radio
} from 'lucide-react';

const FeatureCard = ({ to, icon: Icon, label, color }: { to: string, icon: any, label: string, color: string }) => (
  <Link to={to} className="bg-white p-4 rounded-xl shadow-sm flex flex-col items-center justify-center gap-3 active:scale-95 transition-transform border border-gray-100">
    <div className={`p-3 rounded-full ${color} text-white shadow-md`}>
      <Icon size={24} />
    </div>
    <span className="text-sm font-medium text-gray-700">{label}</span>
  </Link>
);

const Dashboard = () => {
  const { role } = useContext(RoleContext);

  const getFeatures = () => {
    const common = [
      { to: '/live', icon: Radio, label: '直播讲座', color: 'bg-rose-500' },
    ];

    switch (role) {
      case UserRole.TEACHER:
        return [
          { to: '/evaluation', icon: MessageSquare, label: '随堂评教', color: 'bg-indigo-500' },
          { to: '/stats', icon: BarChart2, label: '课堂答题', color: 'bg-cyan-500' }, // Covers Stats & Quiz
          { to: '/stats', icon: PenTool, label: '课堂测验', color: 'bg-sky-500' },
          { to: '/attendance', icon: CalendarCheck, label: '考勤管理', color: 'bg-emerald-500' },
          { to: '/homework', icon: BookOpen, label: '作业布置', color: 'bg-orange-500' },
          ...common
        ];
      case UserRole.SUPERVISOR:
        return [
          { to: '/patrol', icon: Eye, label: '在线巡课', color: 'bg-blue-600' },
          { to: '/supervision', icon: ClipboardCheck, label: '督导听课', color: 'bg-purple-600' },
          ...common
        ];
      case UserRole.STUDENT:
        return [
          { to: '/homework', icon: BookOpen, label: '我的作业', color: 'bg-orange-500' },
          { to: '/attendance', icon: CalendarCheck, label: '我的考勤', color: 'bg-emerald-500' },
          { to: '/evaluation', icon: MessageSquare, label: '参与评教', color: 'bg-indigo-500' },
          ...common
        ];
      default:
        return common;
    }
  };

  return (
    <div className="p-4 space-y-6">
      {/* Banner */}
      <div className="bg-gradient-to-r from-indigo-600 to-purple-600 rounded-2xl p-6 text-white shadow-lg">
        <h2 className="text-xl font-bold mb-1">欢迎回来, {role === UserRole.TEACHER ? '张老师' : role === UserRole.STUDENT ? '李同学' : '督导员'}</h2>
        <p className="text-indigo-100 text-sm opacity-90">今天是 2023年10月27日 星期五</p>
      </div>

      {/* Quick Actions Grid */}
      <div>
        <h3 className="text-base font-bold text-gray-800 mb-4 px-1">
          {role === UserRole.SUPERVISOR ? '督导工作台' : role === UserRole.TEACHER ? '教学管理' : '学习中心'}
        </h3>
        <div className="grid grid-cols-3 gap-3">
          {getFeatures().map((feature, idx) => (
            <FeatureCard key={idx} {...feature} />
          ))}
        </div>
      </div>

      {/* Recent Activity / Notification Placeholder */}
      <div className="bg-white rounded-xl shadow-sm p-4 border border-gray-100">
        <div className="flex justify-between items-center mb-3">
          <h3 className="font-bold text-gray-800">最新通知</h3>
          <span className="text-xs text-gray-400">更多</span>
        </div>
        <div className="space-y-3">
          <div className="flex gap-3 items-start pb-3 border-b border-gray-50 last:border-0 last:pb-0">
            <div className="w-2 h-2 rounded-full bg-red-500 mt-1.5 shrink-0"></div>
            <div>
              <p className="text-sm text-gray-700 font-medium line-clamp-1">关于下周二全校网络维护的通知</p>
              <p className="text-xs text-gray-400 mt-1">教务处 • 10分钟前</p>
            </div>
          </div>
          <div className="flex gap-3 items-start">
            <div className="w-2 h-2 rounded-full bg-gray-300 mt-1.5 shrink-0"></div>
            <div>
              <p className="text-sm text-gray-700 font-medium line-clamp-1">新的评教任务已发布</p>
              <p className="text-xs text-gray-400 mt-1">系统 • 2小时前</p>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState } from 'react';
import { MapPin, List, Video, Search } from 'lucide-react';
import { COURSES } from '../services/mockData';

const Patrol = () => {
  const [mode, setMode] = useState<'list' | 'map'>('list');

  return (
    <div className="h-full flex flex-col">
      {/* Mode Switcher */}
      <div className="bg-white p-2 flex border-b border-gray-200">
        <div className="flex bg-gray-100 rounded-lg p-1 w-full">
          <button 
            onClick={() => setMode('list')}
            className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-md text-sm font-medium transition-all ${mode === 'list' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500'}`}
          >
            <List size={16} /> 课表巡课
          </button>
          <button 
            onClick={() => setMode('map')}
            className={`flex-1 flex items-center justify-center gap-2 py-2 rounded-md text-sm font-medium transition-all ${mode === 'map' ? 'bg-white text-indigo-600 shadow-sm' : 'text-gray-500'}`}
          >
            <MapPin size={16} /> 地理位置巡课
          </button>
        </div>
      </div>

      {/* Content */}
      <div className="flex-1 p-4 overflow-y-auto">
        {mode === 'list' ? (
          <div className="space-y-4">
            <div className="relative">
               <Search className="absolute left-3 top-3 text-gray-400" size={18} />
               <input type="text" placeholder="搜索教室、教师或课程" className="w-full bg-white border border-gray-200 pl-10 pr-4 py-2.5 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500" />
            </div>

            {COURSES.map(course => (
              <div key={course.id} className="bg-white rounded-xl p-4 shadow-sm border border-gray-100">
                <div className="flex justify-between items-start mb-3">
                  <div>
                    <h3 className="font-bold text-gray-800 text-lg">{course.location}</h3>
                    <p className="text-sm text-gray-500 mt-1">{course.name}</p>
                  </div>
                  <span className={`px-2 py-1 rounded text-xs font-medium ${course.status === 'active' ? 'bg-green-100 text-green-700' : 'bg-gray-100 text-gray-500'}`}>
                    {course.status === 'active' ? '授课中' : '休息中'}
                  </span>
                </div>
                <div className="flex justify-between items-center text-sm text-gray-600">
                  <span>{course.teacher}</span>
                  <span>{course.class_name}</span>
                </div>
                {course.status === 'active' && (
                  <div className="mt-4 pt-4 border-t border-gray-100 flex gap-2">
                    <button className="flex-1 bg-indigo-50 text-indigo-600 py-2 rounded-lg text-sm font-medium flex items-center justify-center gap-2">
                      <Video size={16} /> 进入直播
                    </button>
                  </div>
