                    <span className="text-green-600 font-bold">12 正在上课</span>
                </div>
                 <div className="bg-white p-3 rounded-lg shadow-sm flex justify-between items-center opacity-90">
                    <span>实验楼 (15)</span>
                    <span className="text-green-600 font-bold">8 正在上课</span>
                </div>
            </div>
          </div>
        )}
      </div>
