};

export default Patrol;

import React, { useContext } from 'react';
import { RoleContext } from '../App';
import { UserRole } from '../types';
import { HOMEWORK_LIST } from '../services/mockData';
import { FileText, Paperclip, Upload, CheckCircle, Clock } from 'lucide-react';

const Homework = () => {
  const { role } = useContext(RoleContext);

  // Reusing same layout for both just to show the data, 
  // normally Teacher view would be 'Create Homework' and 'Grade Homework'

  return (
    <div className="p-4">
      {role === UserRole.TEACHER && (
         <div className="mb-6 flex justify-end">
            <button className="bg-indigo-600 text-white px-4 py-2 rounded-lg text-sm font-bold shadow-md flex items-center gap-2">
                <FileText size={16} /> 发布新作业
            </button>
         </div>
      )}

      <div className="space-y-4">
        {HOMEWORK_LIST.map((hw) => (
            <div key={hw.id} className="bg-white rounded-xl p-5 shadow-sm border border-gray-100">
                <div className="flex justify-between items-start mb-2">
                    <span className="text-xs text-indigo-600 font-bold bg-indigo-50 px-2 py-1 rounded mb-2 inline-block">
                        {hw.course}
                    </span>
                    <span className={`text-xs px-2 py-1 rounded font-medium flex items-center gap-1
                        ${hw.status === 'pending' ? 'bg-yellow-100 text-yellow-700' : 
                          hw.status === 'submitted' ? 'bg-blue-100 text-blue-700' : 
                          'bg-green-100 text-green-700'}`}>
                        {hw.status === 'pending' && <Clock size={12} />}
                        {hw.status === 'graded' && <CheckCircle size={12} />}
                        {hw.status === 'pending' ? '未提交' : hw.status === 'submitted' ? '已提交' : '已批改'}
                    </span>
                </div>

                <h3 className="font-bold text-gray-800 text-lg mb-2">{hw.title}</h3>
                <p className="text-sm text-gray-500 mb-4">截止时间：{hw.deadline}</p>

                <div className="bg-gray-50 rounded-lg p-3 mb-4 flex items-center gap-3">
                    <div className="w-8 h-8 bg-gray-200 rounded flex items-center justify-center text-gray-500">
                        <Paperclip size={16} />
                    </div>
                    <div className="flex-1">
                        <p className="text-xs font-medium text-gray-700 truncate">作业附件_习题.pdf</p>
                        <p className="text-[10px] text-gray-400">2.4 MB</p>
                    </div>
                    <button className="text-indigo-600 text-xs font-medium">预览</button>
                </div>

                {role === UserRole.STUDENT && (
                    <div className="border-t border-gray-100 pt-4 flex justify-between items-center">
                        {hw.status === 'graded' ? (
                            <span className="text-lg font-bold text-green-600">{hw.score} 分</span>
                        ) : (
                            <span className="text-xs text-gray-400">
                                {hw.status === 'submitted' ? '等待老师批改' : '请在截止日期前提交'}
                            </span>
                        )}

                        {hw.status === 'pending' && (
                            <button className="bg-indigo-600 text-white text-sm px-4 py-2 rounded-lg shadow-sm active:bg-indigo-700 flex items-center gap-2">
                                <Upload size={14} /> 提交作业
                            </button>
                        )}
                    </div>
                )}

                {role === UserRole.TEACHER && (
                    <div className="border-t border-gray-100 pt-4 flex justify-between items-center text-sm">
                        <span className="text-gray-500">已提交: 42/45</span>
                        <button className="text-indigo-600 font-medium">去批改 &rarr;</button>
                    </div>
                )}
            </div>
        ))}
      </div>
    </div>
  );
};

export default Homework;

