// Role Context
export const RoleContext = React.createContext<{
  role: UserRole;
  setRole: (role: UserRole) => void;
  isAuthenticated: boolean;
  setIsAuthenticated: (auth: boolean) => void;
}>({ 
  role: UserRole.TEACHER, 
  setRole: () => {}, 
