const AppContent = () => {
  const location = useLocation();
  const { isAuthenticated, role } = React.useContext(RoleContext);

  if (!isAuthenticated) {
    return <Login />;
  }

  const getTitle = () => {
    switch(location.pathname) {
      case '/': return role === UserRole.STUDENT ? '我的课堂' : '工作台';
      case '/patrol': return '在线巡课';
      case '/supervision': return '督导听课';
      case '/evaluation': return '随堂评教';
      case '/homework': return '我的作业';
      case '/attendance': return '签到记录';
      case '/stats': return '课堂数据';
      case '/live': return '讲座直播';
      case '/profile': return '个人中心';
      case '/sign-in': return '课堂签到';
      default: return '智慧课堂';
    }
  };

  // Hide header for specific pages if needed, but keeping consistent for now
  const shouldShowHeader = !location.pathname.startsWith('/classroom/'); 

  return (
    <div className="min-h-screen bg-gray-50 pb-20">
      {shouldShowHeader && <Header title={getTitle()} canGoBack={location.pathname !== '/' && location.pathname !== '/live' && location.pathname !== '/profile' && location.pathname !== '/homework'} />}
      <Routes>
        <Route path="/" element={<Dashboard />} />
        <Route path="/patrol" element={<Patrol />} />
        <Route path="/supervision" element={<Supervision />} />
        <Route path="/evaluation" element={<Evaluation />} />
        <Route path="/homework" element={<Homework />} />
        <Route path="/attendance" element={<Attendance />} />
        <Route path="/stats" element={<Stats />} />
        <Route path="/live" element={<Live />} />
        <Route path="/profile" element={<ProfilePage />} />
        <Route path="/sign-in" element={<SignIn />} />
        <Route path="/classroom/:id" element={<ClassroomDetail />} />
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
      <BottomNav />
    </div>
  );
};

const App = () => {
  const [role, setRole] = useState<UserRole>(UserRole.STUDENT); // Default to STUDENT for this demo
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  return (
    <RoleContext.Provider value={{ role, setRole, isAuthenticated, setIsAuthenticated }}>
      <HashRouter>
        <AppContent />
      </HashRouter>
    </RoleContext.Provider>
  );
};

export default App;

