interface FeatureCardProps {
  to: string;
  icon: any;
  label: string;
  color: string;
  onClick?: () => void;
}

const FeatureCard: React.FC<FeatureCardProps> = ({ to, icon: Icon, label, color, onClick }) => {
  const baseClassName = "bg-white p-4 rounded-xl shadow-sm flex flex-col items-center justify-center gap-3 active:scale-95 transition-transform border border-gray-100";

  const content = (
    <>
      <div className={`p-3 rounded-full ${color} text-white shadow-md`}>
        <Icon size={24} />
      </div>
      <span className="text-sm font-medium text-gray-700">{label}</span>
    </>
  );

  if (onClick) {
    return (
      <button onClick={onClick} className={`w-full ${baseClassName}`}>
        {content}
      </button>
    );
  }

  return (
    <Link to={to} className={baseClassName}>
      {content}
    </Link>
  );
};

