      switch (activeTab) {
          case 'todo':
              return HOMEWORK_LIST.filter(hw => hw.status === 'pending');
          case 'overdue':
              return HOMEWORK_LIST.filter(hw => hw.status === 'overdue' || hw.status === 'returned');
          case 'history':
              return HOMEWORK_LIST.filter(hw => hw.status === 'submitted' || hw.status === 'graded');
